  ('dietitian-moex-10733', 'dietitian', 'dietitian-moex-094-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列醣類何者屬於變旋異構物（anomers）？ D-葡萄糖（D-glucose）與D-果糖（D-fructose）  D-半乳糖（D-galactose）與D-葡萄糖（D-glucose） D-葡萄糖（D-glucose）與D-甘露糖（D-mannose）   -D-葡萄糖（ -D-glucose）與 -D-葡萄糖（ -D-glucose）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "cc2d54fbf051", "answer_pdf_sha1": "dfeb01e9d1ae", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
